1	// claim-office.ts
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: string; items: unknown[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	export const processScenario = (scenario: Scenario): ScenarioResult => {
13	  return { results: [{ premium: 5 }] };
14	};
15

1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { processScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  describe("quotes: basics", () => {
7	    it("should return premium 5 for a quote with an empty item list (processing fee only)", () => {
8	      const scenario = {
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      };
12	
13	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
14	    });
15	    it.todo("should return premium 115 for a single sword (100 base + 10% first-insurance + 5 fee)");
16	    it.todo("should return premium 71 for a single amulet (60 base)");
17	    it.todo("should return premium 93 for a single staff (80 base)");
18	    it.todo("should return premium 49 for a single potion (40 base)");
19	    it.todo("should return one result per step in the scenario");
20	  });
21	
22	  describe("quotes: components and block", () => {
23	    it.todo("should return premium 33 for a single rune (25 base, final premium rounded up)");
24	    it.todo("should return premium 60 for 2 runes (50 base, no block)");
25	    it.todo("should return premium 71 for exactly 3 runes (block rate of 60 base)");
26	    it.todo("should return premium 115 for 4 runes (100 base, block requires exactly 3)");
27	    it.todo("should return premium 198 for 7 runes (175 base, no block)");
28	    it.todo("should return premium 88 for 2 runes and 1 moonstone (75 base, no block across types)");
29	    it.todo("should return premium 137 for 3 runes and 3 moonstones (two blocks, 120 base)");
30	  });
31	
32	  describe("quotes: item modifiers", () => {
33	    it.todo("should add 50% of the item base premium for a cursed item (cursed sword -> 165)");
34	    it.todo("should add 30% of the item base premium for enchantment level 5 or higher (sword ench 5 -> 145)");
35	  });
36	
37	  describe("quotes: policy modifiers", () => {
38	    it.todo("should subtract 20% loyalty discount for customers with 2 or more years (sword, 2 years -> 95)");
39	    it.todo("should subtract 15% follow-up discount on each quote after the first in the scenario (second sword quote -> 100)");
40	  });
41	
42	  describe("quotes: integration examples", () => {
43	    it.todo("should return premium 165 for a newcomer with a cursed steel sword of enchantment 3");
44	    it.todo("should return premium 160 for a 3-year customer's second quote with a cursed steel sword of enchantment 7");
45	  });
46	
47	  describe("claims: payouts", () => {
48	    it.todo("should pay damage minus 100 deductible for a standard item (steel sword ench 3, damage 500 -> payout 400)");
49	    it.todo("should pay 100 for a rune damaged at 200");
50	    it.todo("should reimburse 50% of the damage before deductible for enchantment 8 or higher (steel sword ench 9, damage 1000 -> payout 400)");
51	    it.todo("should reimburse the full damage minus deductible for dragon material below enchantment 8 (dragon sword ench 5, damage 800 -> payout 700)");
52	    it.todo("should apply the 50% rule when both dragon material and enchantment 8+ apply (dragon sword ench 9, damage 1000 -> payout 400)");
53	    it.todo("should round the final payout down to a whole G (steel sword ench 9, damage 999 -> payout 399)");
54	  });
55	
56	  describe("claims: deductible per damaged item", () => {
57	    it.todo("should apply the deductible once per damaged item (sword damage 500 + amulet damage 300 -> payout 600)");
58	    it.todo("should apply a separate deductible to each damage entry of the same type (two insured swords, two sword damage entries)");
59	  });
60	
61	  describe("claims: payout cap", () => {
62	    it.todo("should report remainingCap as twice the insurance sum minus the payout (sword policy, claim 1500 -> payout 1400, remainingCap 600)");
63	    it.todo("should reduce the payout to the remaining cap on a later claim (second 1500 claim -> payout 600, remainingCap 0)");
64	    it.todo("should compute the cap from unmodified insurance values of all items (two swords -> cap 4000)");
65	  });
66	
67	  describe("errors", () => {
68	    it.todo("should throw for an unknown item type in a quote (e.g. broomstick)");
69	    it.todo("should throw for a damage entry whose item type is not covered by the policy");
70	    it.todo("should throw when more damage entries of a type are claimed than items of that type are covered");
71	    it.todo("should throw for a negative damage amount");
72	  });
73	});
